 81→//----- difinitions for L2C_begin -----
 82→#define __I                     volatile const	/* 'read only' permissions      */
 83→#define __O                     volatile        /* 'write only' permissions     */
 84→#define __IO                    volatile        /* 'read / write' permissions   */
