259→void init_l2c_hpm()
260→{
261→    DEV_L2C->HPMCTL0 = 0x201;
262→    DEV_L2C->REG.HPMCNT[0] = 0;
263→    DEV_L2C->REG.HPMCNT[1] = 0;
264→}
265→
266→void get_l2c_hpm()
267→{
268→    l2c_access = DEV_L2C->REG.HPMCNT[0];
269→    l2c_miss = DEV_L2C->REG.HPMCNT[1];
270→}
