443→        printf("The inst count is %u\n", (unsigned int)inst);
444→    }
445→
446→    if(cycle > __UINT32_MAX__)
447→    {
448→        printf("WARNING !!! The cycle value is larger than 32-bit.\n Print the value in hex.\n");
449→        printf("The cycle count is 0x%08x%08x\n", (unsigned int)(cycle>>32), (unsigned int)cycle);
450→    }
451→    else    //show the performance data in 32-bit
452→    {
453→        printf("The cycle count is %u\n", (unsigned int)cycle);
454→    }
455→
456→#ifdef ENA_CACHE_PFM
457→    printf("The D$ load access is %zu\n", dcache_load_access);
458→    printf("The D$ load miss is %zu\n", dcache_load_miss);
459→    printf("The D$ store miss is %zu\n", dcache_store_miss);
460→    printf("The D$ miss stall cycle is %zu\n", data_cache_stall_cycle);
461→#endif
