463→    printf("L2C access: %zu\n", l2c_access);
464→    printf("L2C miss: %zu\n", l2c_miss);
465→#endif
466→#else
467→    printf("The inst count is %u\n", inst);
468→    printf("The cycle count is %u\n", cycle);
469→#endif
470→
