472→    unsigned int ONEMHZ = 1000000;
473→    float32_t  mhzbycycle = (float32_t) ONEMHZ / cycle * 100.0f;
474→    printf("The MHZ per cycle count is %5.2f%%\n", mhzbycycle);
475→#endif
476→}
