416→__attribute__((noinline))
417→void enable_fs_and_vs()
418→{
419→#ifdef ENA_FS_VS
420→// #if 1
421→    {
422→        //Set MSTATUS.FS = 2 (clean) to avoid post FPU instructions raise exception in other simulator (Imperas).
423→        unsigned long csr_mstatus;
424→        const unsigned long mask_fs = (3L << 13);
425→        const unsigned long fs_clean = (2L << 13);
426→
427→        PRINTF_DBG("\nSet FPU...\n");
428→        PRINTF_DBG("Setting MSTATUS.FS = 2 (=clean) ...\n");
429→
430→        csr_mstatus = __nds__read_and_clear_csr(mask_fs, NDS_MSTATUS);
431→        //PRINTF_DBG("Original MSTATUS CSR = 0x%016lX\n", csr_mstatus);
432→
433→        //csr_mstatus = __nds__read_csr(NDS_MSTATUS);
434→        // PRINTF_DBG("After read and clear, MSTATUS CSR = 0x%016lX\n", csr_mstatus);
435→
436→        csr_mstatus &= ~mask_fs;
437→        csr_mstatus |= fs_clean;
438→        PRINTF_DBG("New MSTATUS value = 0x%016lX\n", csr_mstatus);
439→        __nds__write_csr(csr_mstatus, NDS_MSTATUS);
440→
441→        //Read again to verify it.
442→        csr_mstatus = __nds__read_csr(NDS_MSTATUS);
443→        PRINTF_DBG("MSTATUS CSR = 0x%016lX\n", csr_mstatus);
444→        PRINTF_DBG("FPU is set to clean.\n\n");
445→    }
446→
447→    {
448→        //Enable VPU
449→        unsigned long csr_mstatus;
450→#if (NDS_VEC_RVV_VERSION == 80)     //for v-ext 0.8
451→        const unsigned long mask_vs = (3L << 23);
452→        const unsigned long vs_clean = (2L << 23);
453→#else   //for rvv-0.9 or higher
454→        const unsigned long mask_vs = (3L << 9);
455→        const unsigned long vs_clean = (2L << 9);
456→#endif
457→
458→        PRINTF_DBG("Set VPU...\n");
459→        PRINTF_DBG("Setting MSTATUS.VS = 2 (=clean) ...\n");
460→        csr_mstatus = __nds__read_and_clear_csr(mask_vs, NDS_MSTATUS);
461→        PRINTF_DBG("After read and clear, MSTATUS CSR = 0x%016X\n", csr_mstatus);
462→
463→        //csr_mstatus = __nds__read_csr(NDS_MSTATUS);
464→        //PRINTF_DBG("Original MSTATUS CSR = 0x%08X\n", csr_mstatus);
465→
466→        csr_mstatus &= ~mask_vs;
467→        csr_mstatus |= vs_clean;
468→        PRINTF_DBG("New MSTATUS value = 0x%016lX\n", csr_mstatus);
469→        __nds__write_csr(csr_mstatus, NDS_MSTATUS);
470→
471→        //Read again to verify it.
472→        csr_mstatus = __nds__read_csr(NDS_MSTATUS);
473→        PRINTF_DBG("MSTATUS CSR = 0x%016lX\n", csr_mstatus);
474→        PRINTF_DBG("VPU is set to clean.\n\n");
475→    }
476→#endif
477→
478→#ifdef ENA_ACE_RVV
479→    {
480→        unsigned long csr_mmisc_ctl;
481→        const unsigned long mask_aces = (3L << 4);
482→        const unsigned long aces_initial = (1L << 4);
483→
484→        csr_mmisc_ctl = __nds__read_csr(NDS_MMISC_CTL);
